private Path resolveAssetLocation(String collection, String name) throws IOException {

        Path base = BASE.toAbsolutePath().normalize();
        Path target = base.resolve(collection).resolve(name).normalize();

        if (!target.startsWith(base)) {
            throw new IOException("Invalid asset path");
        }

        return target;
    }
